import React, { useState, useEffect } from 'react';
import { internshipApi } from '../../services/api';
import { useAuth } from '../../context/AuthContext';

const STATUS_CONFIG = {
  PENDING:              { bg: 'bg-amber-100',  text: 'text-amber-700',  label: 'Pending',   dot: 'bg-amber-500' },
  SHORTLISTED:          { bg: 'bg-blue-100',   text: 'text-blue-700',   label: 'Shortlisted', dot: 'bg-blue-500' },
  INTERVIEW_SCHEDULED:  { bg: 'bg-violet-100', text: 'text-violet-700', label: 'Interview', dot: 'bg-violet-500' },
  ACCEPTED:             { bg: 'bg-green-100',  text: 'text-green-700',  label: 'Accepted',  dot: 'bg-green-500' },
  REJECTED:             { bg: 'bg-red-100',    text: 'text-red-700',    label: 'Rejected',  dot: 'bg-red-500' },
  WITHDRAWN:            { bg: 'bg-slate-100',  text: 'text-slate-500',  label: 'Withdrawn', dot: 'bg-slate-400' },
};

const InternshipsPage = () => {
  const { user } = useAuth();
  const isAdmin = user?.role === 'ADMIN' || user?.role === 'SUPER_ADMIN';

  const [offers, setOffers] = useState([]);
  const [myApps, setMyApps] = useState([]);
  const [tab, setTab] = useState('offers');
  const [coverLetter, setCoverLetter] = useState('');
  const [cvFile, setCvFile] = useState(null);
  const [applyingTo, setApplyingTo] = useState(null);
  const [feedback, setFeedback] = useState({ msg: '', type: 'success' });
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    setLoading(true);
    internshipApi.getOffers()
      .then(({ data }) => setOffers(data))
      .catch(() => {})
      .finally(() => setLoading(false));
    if (!isAdmin) {
      internshipApi.myApplications().then(({ data }) => setMyApps(data)).catch(() => {});
    }
  }, [isAdmin]);

  const notify = (msg, type = 'success') => {
    setFeedback({ msg, type });
    setTimeout(() => setFeedback({ msg: '', type: 'success' }), 3500);
  };

  const handleApply = async (offerId) => {
    setSubmitting(true);
    try {
      await internshipApi.apply(offerId, coverLetter, cvFile);
      notify('Application submitted successfully!');
      setApplyingTo(null);
      setCoverLetter('');
      setCvFile(null);
      internshipApi.myApplications().then(({ data }) => setMyApps(data));
    } catch (err) {
      notify(err.response?.data?.message || 'Application failed.', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const daysUntil = (deadline) => {
    if (!deadline) return null;
    return Math.ceil((new Date(deadline) - new Date()) / (1000 * 60 * 60 * 24));
  };

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">

      {/* Page header */}
      <div>
        <h1 className="text-2xl font-bold text-slate-900">Internships</h1>
        <p className="text-slate-500 text-sm mt-0.5">Discover and apply for internship opportunities</p>
      </div>

      {/* Feedback toast */}
      {feedback.msg && (
        <div className={`flex items-center gap-2 px-4 py-3 rounded-xl text-sm font-medium ${
          feedback.type === 'error'
            ? 'bg-red-50 border border-red-200 text-red-700'
            : 'bg-green-50 border border-green-200 text-green-700'
        }`}>
          <svg className="w-4 h-4 shrink-0" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
            {feedback.type === 'error'
              ? <path d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z"/>
              : <path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/>}
          </svg>
          {feedback.msg}
        </div>
      )}

      {/* Stats bar — student only */}
      {!isAdmin && myApps.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: 'Applied', value: myApps.length, from: 'from-blue-500', to: 'to-blue-600' },
            { label: 'Shortlisted', value: myApps.filter((a) => a.status === 'SHORTLISTED').length, from: 'from-violet-500', to: 'to-violet-600' },
            { label: 'Accepted', value: myApps.filter((a) => a.status === 'ACCEPTED').length, from: 'from-green-500', to: 'to-emerald-600' },
          ].map(({ label, value, from, to }) => (
            <div key={label} className={`bg-gradient-to-br ${from} ${to} rounded-2xl p-4 text-white shadow-sm`}>
              <p className="text-2xl font-bold">{value}</p>
              <p className="text-xs opacity-80 mt-0.5">{label}</p>
            </div>
          ))}
        </div>
      )}

      {/* Tabs */}
      <div className="flex border-b border-slate-200 gap-1">
        <button
          onClick={() => setTab('offers')}
          className={`px-4 py-2.5 text-sm font-medium border-b-2 transition ${
            tab === 'offers' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          Available Offers
          {offers.length > 0 && (
            <span className="ml-2 bg-blue-100 text-blue-600 text-xs font-semibold px-1.5 py-0.5 rounded-full">
              {offers.length}
            </span>
          )}
        </button>
        {!isAdmin && (
          <button
            onClick={() => setTab('my')}
            className={`px-4 py-2.5 text-sm font-medium border-b-2 transition ${
              tab === 'my' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
            }`}
          >
            My Applications
            {myApps.length > 0 && (
              <span className="ml-2 bg-slate-100 text-slate-600 text-xs font-semibold px-1.5 py-0.5 rounded-full">
                {myApps.length}
              </span>
            )}
          </button>
        )}
      </div>

      {/* ── OFFERS TAB ── */}
      {tab === 'offers' && (
        <>
          {loading ? (
            <div className="flex justify-center py-16">
              <div className="w-8 h-8 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"/>
            </div>
          ) : offers.length === 0 ? (
            <div className="text-center py-16 bg-white rounded-2xl border border-slate-200">
              <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
                  <path d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"/>
                </svg>
              </div>
              <p className="text-slate-600 font-medium">No offers available</p>
              <p className="text-slate-400 text-sm mt-1">Check back later for new opportunities</p>
            </div>
          ) : (
            <div className="space-y-4">
              {offers.map((offer) => {
                const days = daysUntil(offer.applicationDeadline);
                const urgent = days != null && days <= 7;
                const expired = days != null && days <= 0;
                return (
                  <div key={offer.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="p-5">
                      <div className="flex items-start gap-4">
                        <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-blue-100 to-blue-200 flex items-center justify-center shrink-0 text-blue-700 font-bold text-lg">
                          {(offer.companyName || 'C')[0].toUpperCase()}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-start justify-between gap-3 flex-wrap">
                            <div>
                              <h3 className="font-semibold text-slate-900">{offer.title}</h3>
                              <p className="text-sm text-slate-500 mt-0.5">{offer.companyName}</p>
                            </div>
                            <div className="flex items-center gap-2 flex-wrap shrink-0">
                              {offer.durationMonths && (
                                <span className="text-xs bg-slate-100 text-slate-600 px-2.5 py-1 rounded-full font-medium">
                                  {offer.durationMonths} months
                                </span>
                              )}
                              {offer.requiredDepartment && (
                                <span className="text-xs bg-blue-50 text-blue-700 px-2.5 py-1 rounded-full font-medium">
                                  {offer.requiredDepartment}
                                </span>
                              )}
                              {days != null && (
                                <span className={`text-xs px-2.5 py-1 rounded-full font-semibold ${
                                  expired ? 'bg-slate-100 text-slate-500'
                                    : urgent ? 'bg-red-100 text-red-700'
                                    : 'bg-amber-100 text-amber-700'
                                }`}>
                                  {expired ? 'Deadline passed' : `${days}d left`}
                                </span>
                              )}
                            </div>
                          </div>
                          {offer.description && (
                            <p className="text-sm text-slate-600 mt-2 line-clamp-2">{offer.description}</p>
                          )}
                          {!isAdmin && applyingTo !== offer.id && (
                            <button
                              onClick={() => setApplyingTo(offer.id)}
                              disabled={expired}
                              className="mt-3 px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-200 disabled:text-slate-400 text-white rounded-xl text-xs font-semibold transition"
                            >
                              Apply Now
                            </button>
                          )}
                        </div>
                      </div>

                      {applyingTo === offer.id && (
                        <div className="mt-5 border-t border-slate-100 pt-5 space-y-4">
                          <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1.5">
                              Cover Letter
                            </label>
                            <textarea
                              rows={3}
                              className="w-full border border-slate-200 rounded-xl px-3.5 py-2.5 text-sm bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-400 resize-none"
                              placeholder="Write a brief cover letter explaining your interest and qualifications..."
                              value={coverLetter}
                              onChange={(e) => setCoverLetter(e.target.value)}
                            />
                          </div>
                          <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1.5">
                              CV / Résumé <span className="text-red-500">*</span>
                            </label>
                            <label className={`flex items-center gap-3 border-2 border-dashed rounded-xl px-4 py-3.5 cursor-pointer transition ${
                              cvFile ? 'border-green-400 bg-green-50' : 'border-slate-200 hover:border-blue-400 bg-slate-50'
                            }`}>
                              <svg className={`w-5 h-5 shrink-0 ${cvFile ? 'text-green-500' : 'text-slate-400'}`} fill="none" stroke="currentColor" strokeWidth={1.8} viewBox="0 0 24 24">
                                <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/>
                              </svg>
                              <span className={`text-sm ${cvFile ? 'text-green-700 font-medium' : 'text-slate-500'}`}>
                                {cvFile ? cvFile.name : 'Click to upload PDF (max 5MB)'}
                              </span>
                              <input type="file" accept=".pdf" className="hidden" onChange={(e) => setCvFile(e.target.files[0] || null)} />
                            </label>
                          </div>
                          <div className="flex gap-2">
                            <button
                              onClick={() => handleApply(offer.id)}
                              disabled={submitting || !cvFile}
                              className="px-5 py-2.5 bg-green-600 hover:bg-green-700 disabled:bg-slate-200 disabled:text-slate-400 text-white rounded-xl text-sm font-semibold transition"
                            >
                              {submitting ? 'Submitting…' : 'Submit Application'}
                            </button>
                            <button
                              onClick={() => { setApplyingTo(null); setCoverLetter(''); setCvFile(null); }}
                              className="px-5 py-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl text-sm font-semibold transition"
                            >
                              Cancel
                            </button>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </>
      )}

      {/* ── MY APPLICATIONS TAB ── */}
      {tab === 'my' && (
        <>
          {myApps.length === 0 ? (
            <div className="text-center py-16 bg-white rounded-2xl border border-slate-200">
              <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
                  <path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"/>
                </svg>
              </div>
              <p className="text-slate-600 font-medium">No applications yet</p>
              <p className="text-slate-400 text-sm mt-1">Browse available offers and apply to get started</p>
            </div>
          ) : (
            <div className="space-y-3">
              {myApps.map((app) => {
                const cfg = STATUS_CONFIG[app.status] || { bg: 'bg-slate-100', text: 'text-slate-600', label: app.status, dot: 'bg-slate-400' };
                return (
                  <div key={app.id} className="bg-white rounded-xl border border-slate-200 shadow-sm px-5 py-4 flex items-center gap-4">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-100 to-blue-200 flex items-center justify-center text-blue-700 font-bold text-sm shrink-0">
                      {(app.companyName || 'C')[0].toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-semibold text-slate-900 text-sm truncate">{app.offerTitle}</p>
                      <p className="text-xs text-slate-400 mt-0.5">{app.companyName}</p>
                      {app.cvDownloadUrl && (
                        <a
                          href={`${process.env.REACT_APP_API_URL || 'http://localhost:8081'}${app.cvDownloadUrl}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center gap-1 text-xs text-blue-600 hover:underline mt-1"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                            <path d="M12 10v6m0 0l-3-3m3 3l3-3M3 17V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z"/>
                          </svg>
                          {app.cvFileName || 'Download CV'}
                        </a>
                      )}
                      {app.adminNote && (
                        <p className="text-xs text-slate-500 mt-1 italic">"{app.adminNote}"</p>
                      )}
                    </div>
                    <span className={`inline-flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-full shrink-0 ${cfg.bg} ${cfg.text}`}>
                      <span className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`} />
                      {cfg.label}
                    </span>
                  </div>
                );
              })}
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default InternshipsPage;
